57	export function validateTitle(value: unknown): string | null {
58	  if (value === null || value === undefined) return null;
59	  if (typeof value !== 'string') {
60	    throw invalid('title must be a string or null');
61	  }
62	  if (value.length === 0 || value.length > TITLE_MAX) {
63	    throw invalid(`title must be 1-${TITLE_MAX} chars`);
64	  }
65	  return value;
66	}
