68	export function validateRole(value: unknown): TurnRole {
69	  if (typeof value !== 'string' || !VALID_ROLES.has(value as TurnRole)) {
70	    throw invalid("role must be 'user', 'assistant', or 'tool'");
71	  }
72	  return value as TurnRole;
73	}
