75	export function validateContentBlocks(value: unknown): ContentBlock[] {
76	  // Canonical Anthropic-compatible schema lives in @ax/ipc-protocol; this
77	  // is the single source of truth for both the IPC wire and our JSONB
78	  // column (Invariant I4).
79	  const parsed = ContentBlockArraySchema.safeParse(value);
80	  if (!parsed.success) {
81	    throw invalid(
82	      `contentBlocks must be an array of ContentBlock objects: ${parsed.error.message}`,
83	    );
84	  }
85	  return parsed.data;
86	}
