314	export function createConversationStore(
315	  db: Kysely<ConversationDatabase>,
316	): ConversationStore {
317	  return {
318	    async getByIdNotDeleted(conversationId) {
319	      const row = await db
320	        .selectFrom('conversations_v1_conversations')
321	        .selectAll('conversations_v1_conversations')
322	        .where('conversation_id', '=', conversationId)
323	        .where('deleted_at', 'is', null)
324	        .executeTakeFirst();
325	      return row === undefined ? null : rowToConversation(row);
326	    },
327	
328	    async getByReqIdForUser(userId, reqId) {
329	      // Filter by user_id FIRST so a foreign reqId can't trigger a row
330	      // existence oracle: every miss is identical to "no such row" from
331	      // the caller's perspective. The conversations_v1_conversations_owner
332	      // index covers (user_id, agent_id) — adding active_req_id to the
333	      // WHERE clause is still cheap because user_id alone narrows to a
334	      // single user's rowset.
335	      const row = await db
336	        .selectFrom('conversations_v1_conversations')
337	        .selectAll('conversations_v1_conversations')
338	        .where('user_id', '=', userId)
339	        .where('active_req_id', '=', reqId)
340	        .where('deleted_at', 'is', null)
341	        .executeTakeFirst();
342	      return row === undefined ? null : rowToConversation(row);
343	    },
344	
345	    async listForUser(userId, agentId) {
346	      let q = scopedConversations(db, { userId }).orderBy('created_at', 'desc');
347	      if (agentId !== undefined) {
348	        q = q.where('agent_id', '=', agentId);
349	      }
350	      const rows = await q.execute();
351	      return rows.map(rowToConversation);
352	    },
353	
354	    async create({ userId, agentId, title, runnerType, workspaceRef }) {
355	      const id = mintConversationId();
356	      const now = new Date();
357	      const row = await db
358	        .insertInto('conversations_v1_conversations')
359	        .values({
360	          conversation_id: id,
361	          user_id: userId,
362	          agent_id: agentId,
363	          title,
364	          active_session_id: null,
365	          active_req_id: null,
366	          // Phase B: freeze runner_type + workspace_ref onto the row.
367	          // Pre-Phase-B callers (test fixtures) omit these and the row
368	          // persists as NULL — opaque to the correctness path (I8/I10).
369	          runner_type: runnerType ?? null,
370	          runner_session_id: null,
371	          workspace_ref: workspaceRef ?? null,
372	          last_activity_at: null,
373	          deleted_at: null,
374	          created_at: now,
375	          updated_at: now,
376	        })
377	        .returningAll()
378	        .executeTakeFirstOrThrow();
379	      return rowToConversation(row as ConversationsRow);
380	    },
381	
382	    async softDelete(conversationId) {
383	      const result = await db
384	        .updateTable('conversations_v1_conversations')
385	        .set({ deleted_at: new Date(), updated_at: new Date() })
386	        .where('conversation_id', '=', conversationId)
387	        .where('deleted_at', 'is', null)
388	        .executeTakeFirst();
389	      return Number(result.numUpdatedRows ?? 0n) > 0;
390	    },
391	
392	    async setActiveSession({ conversationId, userId, sessionId, reqId }) {
393	      // Filter by user_id alongside conversation_id so a foreign caller
394	      // can never bind a row they don't own. Non-existence + foreign-user
395	      // both look identical from the caller's perspective: numUpdatedRows
396	      // === 0 → 'not-found' at the plugin layer.
