412	      const result = await db
413	        .updateTable('conversations_v1_conversations')
414	        .set({
415	          active_session_id: null,
416	          active_req_id: null,
417	          updated_at: new Date(),
418	        })
419	        .where('conversation_id', '=', conversationId)
420	        .where('user_id', '=', userId)
421	        .where('deleted_at', 'is', null)
422	        .executeTakeFirst();
423	      return Number(result.numUpdatedRows ?? 0n) > 0;
424	    },
425	
426	    async clearActiveReqId(conversationId, expectedReqId) {
427	      // Compare-and-clear on `active_req_id`. If a fresh reqId has already
428	      // been bound (e.g. a second user message arrived between this turn-
429	      // end being fired and the subscriber running), the WHERE will miss
430	      // and the newer in-flight reqId is preserved. This is essential for
431	      // J6's "no stale clobber" property.
432	      const result = await db
433	        .updateTable('conversations_v1_conversations')
434	        .set({ active_req_id: null, updated_at: new Date() })
435	        .where('conversation_id', '=', conversationId)
436	        .where('active_req_id', '=', expectedReqId)
437	        .where('deleted_at', 'is', null)
438	        .executeTakeFirst();
439	      return Number(result.numUpdatedRows ?? 0n) > 0;
440	    },
