443	      // No user_id filter — host-internal observation of a sandbox
444	      // teardown. We clear active_session_id AND active_req_id together
445	      // because if the session is gone, an in-flight reqId pointing at
446	      // it is dead too.
447	      const result = await db
448	        .updateTable('conversations_v1_conversations')
449	        .set({
450	          active_session_id: null,
451	          active_req_id: null,
452	          updated_at: new Date(),
453	        })
454	        .where('active_session_id', '=', sessionId)
455	        .where('deleted_at', 'is', null)
456	        .executeTakeFirst();
457	      return Number(result.numUpdatedRows ?? 0n);
458	    },
459	
460	    async getMetadata(conversationId) {
461	      const row = await db
